### Fastify with OpenTelemetry Counter (Immediate Initialization)

Source: https://github.com/newrelic/node-newrelic/blob/main/documentation/otel/metrics.md

Adds an OpenTelemetry counter to a Fastify application handler. Metrics are initialized immediately upon application start, which might lead to issues if the agent is not ready.

```javascript
'use strict'

const otel = require('@opentelemetry/api')
const metrics = otel.metrics

const server = require('fastify')({
  logger: {
    level: 'info'
  }
})

server.route({
  path: '/',
  method: 'GET',
  handler (req, res) {
    this.metrics['test-counter'].add(1)
    res.send({ hello: 'world' })
  }
})

server.decorate('metrics', {
  'test-counter': metrics.getMeter('test-meter').createCounter('test-counter')
})

server.listen({ port: 8080 })

```

